```java
public String summary() { // Renamed to follow Java conventions
    // Take a snapshot of the counters to ensure consistency.
    int total = totalSpawns.get();
    int cacheHits = remoteCacheHit.get();
    int remoteExecs = remoteExec.get();
    int localSpawns = local.get();

    int remote = remoteExecs + cacheHits;
    int fallback = total - remote - localSpawns;

